var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"20년 전, 관리 실패의 여파로 발생한 대균열은 프론트 베이의 모든 것을 집어삼켰단다.","JPN":"20年前、管理失敗の影響で発生した大亀裂は、フロントベイのすべてを飲み込んだわ。","ENG":"Twenty years ago, the aftermath of the Administration Failure unleashed a Grand Dimension Crevice that swallowed everything in Front Bay.","TWN":"20年前，因管理失誤引發的大峽谷吞噬了整個前灣。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리와 우리들은 그 재해 속에서 가까스로 살아남은 생존자들이었지.","JPN":"エイバリーと私たちは、あの災害からなんとか生き延びた者同士だった。","ENG":"Avery and the rest of us were the barely surviving remnants of that disaster.","TWN":"艾維利和我們，是那場災難中的倖存者。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들은 살기 위해 서로의 것을 빼앗고, 죽이며 살아남았어.","JPN":"人々は生きるために奪い合い、殺し合った。","ENG":"People stole and killed each other just to live.","TWN":"人們為了生存互相掠奪、殺戮。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"빼앗기지 않기 위해, 죽지 않기 위해 모여든 사람들은 어느새 하나의 집단이 되었지.","JPN":"奪われないために、殺されないために、力を合わせた人々はやがて1つの集団になっていった。","ENG":"To avoid being robbed and to avoid dying, those who gathered together eventually became a single group.","TWN":"為了不被掠奪、為了求生，聚集的人們慢慢形成了一個群體。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것이 에이버리 해적단의 시작이었단다.","JPN":"それがエイバリー海賊団の始まりだったわ。","ENG":"That was the beginning of the Avery Pirates.","TWN":"那就是艾維利海盜團的起源。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"결국 침식체로 인해 고향이 파괴된 우리는 바다로 나왔어.","JPN":"結局、侵食体によって故郷を破壊された私たちは海に出るしかなかった。","ENG":"In the end, with our homeland destroyed by C.O.s, we fled to sea.","TWN":"最終我們的家園被侵蝕體毀了，迫使我們踏上大海。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"살아남기 위해서.","JPN":"生きるために。","ENG":"Just to survive.","TWN":"為了生存。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"정처 없이 바다를 떠돌다 어느 섬에 도착해 본거지로 삼았지.","JPN":"あてもなく海を漂い、とある島に着いた私たちはその島を拠点にしたわ。","ENG":"We drifted without destination until we reached an island and made it our base.","TWN":"我們漂泊無依，直到找到一座島嶼作為落腳點。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이유는 무척이나 단순했단다.","JPN":"理由はとてもシンプルだった。","ENG":"The reason was simple.","TWN":"選擇那裡的理由很簡單。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그곳의 일출이 기가 막혔거든.","JPN":"そこの日の出が絶景だったのよ。","ENG":"The sunrise there was breathtaking.","TWN":"那裡的日出太美了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리는 그곳의 풍경을 모두가 보기를 바랐어.","JPN":"エイバリーはそこの景色をみんなに見てほしいと願ったわ。","ENG":"Avery wanted everyone to see that sight.","TWN":"艾維利希望每個人都能看到這片風景。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이걸 보고 감동한 사람들이 조금이라도 힘을 내지 않을까 생각했거든. ","JPN":"それを見て感動した人々が、少しでも元気を出せるんじゃないかって。 ","ENG":"He thought that maybe it would give people the strength to keep going.","TWN":"哪怕只是一點點，希望因此被感動的人們能振作起來。 "},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리는 바다를 모험하며 얻은 경험을 바탕으로 침식체를 사냥하고, 아티팩트를 가져와 사람들에게 나눠줬지.","JPN":"彼は海を冒険しながら得た経験をもとに、侵食体を狩り、アーティファクトを持ってきて、人々に分け与えたの。","ENG":"Avery hunted the C.O.s on the sea using what he learned from his adventures and shared the Artifacts he brought back.","TWN":"艾維利憑藉海上冒險的經驗狩獵侵蝕體、取得神器並分給人們。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들을 약탈하던 사람들은 에이버리가 가져온 아티팩트를 보곤 바다로 나가기 시작했어.","JPN":"略奪を繰り返していた人々は、彼が持ってきたアーティファクトを見て海に出るようになった。","ENG":"The people who had lived by raiding others saw Avery's Artifacts and began heading out to sea.","TWN":"曾經掠奪他人的人看到艾維利帶回的神器，也開始展開海上之路。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것이 프론트 베이에 해적이 생겨난 이유란다.","JPN":"それが、フロントベイに海賊が生まれた理由なのよ。","ENG":"That's why pirates were born in Front Bay.","TWN":"這就是為什麼前灣會出現海盜的原因。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그렇게 육지의 사람들은 서서히 질서를 되찾았단다.","JPN":"そうやって陸地は徐々に秩序を取り戻していったわ。","ENG":"And slowly, the people on land regained order.","TWN":"陸地上的人們逐漸找回秩序。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"내일을 꿈꾸길 포기한 사람들은 다시 오늘의 별을 바라보며 잠들 수 있게 되었지.","JPN":"明日を夢見ることを諦めていた人々は、再び今日の星を見上げて眠れるようになった。","ENG":"Those who had given up dreaming of tomorrow were once again able to sleep while looking up at the stars.","TWN":"放棄夢想明天的人，也能重新仰望今夜的星空入眠。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"하지만 그런 우리도 피할 수 없는 시간이 찾아왔어.","JPN":"でも、そんな私たちにも避けられない瞬間がやってきたの。","ENG":"But even we couldn't escape the passage of time.","TWN":"然而我們無法逃避的考驗也找上門了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"검은 범람의 발생이었습니다.","JPN":"黒い氾濫が発生したのです。","ENG":"The Black Flood.","TWN":"黑色洪災再次爆發。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"당시 사람들은 바다에서 엄청난 빛기둥이 솟아오른 것은 목격했지만…….","JPN":"当時、人々は海から巨大な光の柱が立つところは目撃したものの……","ENG":"Witnesses saw a massive pillar of light shoot up from the sea...","TWN":"當時人們看到巨大的光柱自海面升起……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 빛기둥 속에서 무엇이 기어 나왔는지는 확인하지 못했으니까요.","JPN":"その光の柱から何が出てきたかは確認できませんでした。","ENG":"But no one saw what crawled out of that pillar of light.","TWN":"卻無法確認從光柱爬出的東西是什麼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"무한 증식형 4종 침식체, 식별명 크라켄은 대균열 속에서 유체 형태로 바다에 부상했습니다.","JPN":"無限増殖型第4種侵食体、識別名クラーケンは大亀裂の中から幼体の形で海に浮上しました。","ENG":"The endlessly multiplying Category 4 C.O., designated Kraken, surfaced from the Grand Dimension Crevice in a larva form.","TWN":"無限增殖型4類侵蝕體，識別名「克拉肯」。以流體形態自大峽谷浮出海面。"},"stage":{"bg":"HORIZON_02_A","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"바다의 모든 것을 닥치는 대로 집어삼킨 녀석은… 어느새 재해를 일으킬 정도로 거대해졌죠.","JPN":"海のすべてを手当たり次第貪り尽くしたそれは……やがて災害を引き起こすほど巨大になっていきました。","ENG":"It devoured everything in the ocean... and grew into a disaster-class monster.","TWN":"吞噬大海一切的它……很快變大到足以引發災難的規模。"},"stage":{"bg":"HORIZON_02_A","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"하늘에서 뚝 떨어진 거대한 UFO.","JPN":"空から落ちてきた1隻の巨大なUFO。","ENG":"A giant UFO falling from the sky.","TWN":"天上掉下的飛船，"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그 당시엔 그렇게 생각했지만, 지금은 로스트 쉽이라 부르는 함선…….","JPN":"当時はそう思ってたけど……今はロストシップと呼ばれている艦船……","ENG":"That's what we thought back then, but now we call it the Lost Ship–","TWN":"當時我們以為是巨型UFO，但那時我們與現在被稱為失落艦船……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"인빈서블과의 첫 만남이었단다.","JPN":"インビンシブルとの出会いもその時だったわね。","ENG":"It was our first encounter with the Invincible.","TWN":"無敵號的第一次邂逅。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그때, 에이버리가 이 모든 일이 외계인의 비밀 실험 때문이라고 소리를 질렀지.","JPN":"あの時、エイバリーがすべては宇宙人の秘密実験のせいだと声を上げたの。","ENG":"At the time, Avery shouted that the whole thing had to be some secret alien experiment.","TWN":"那時艾維利大喊這一切都是外星人的秘密實驗。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};